def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        for j in range(1, 11):
            if j % 2 == 0:
                score += ((-1) ** (j//2)) * (1 / j) * (ratio ** j)
            else:
                score += (1 / j) * (ratio ** j)
        if capacity - item < 0.1 * capacity:
            score *= 2
        elif capacity - item < 0.3 * capacity:
            score *= 1.2
        else:
            score *= 0.8
        if capacity % 2 == 0 and capacity % 3 == 0:
            score -= 0.3
        elif capacity % 2 == 0:
            score -= 0.1
        elif capacity % 3 == 0:
            score -= 0.05
        if item < 0.2 * capacity:
            score += 0.1
        temp = 0
        for k in range(1, int(capacity)+1):
            if k > item and k % 5 == 0:
                temp += np.log(k + ratio+1)
        score += temp * 0.001
        priorities[i] = max(score, 0)
    return priorities
